class Solution:
    def kClosest(self, points, k):
        import heapq
        heap = []
        for p in points:
            d = p[0] * p[0] + p[1] * p[1]
            if len(heap) < k:
                heapq.heappush(heap, (-d, p))
            elif -d > heap[0][0]:
                heapq.heapreplace(heap, (-d, p))
        return [p for _, p in heap]

